namespace sv_8d8308971df64ee7bf94d753abe5eb69.Models;

public class WizardState
{
    // Step 1: Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = new();

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = new();

    // Completion tracking
    public bool Step1Complete { get; set; }
    public bool Step2Complete { get; set; }
    public bool Step3Complete { get; set; }
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_8d8308971df64ee7bf94d753abe5eb69.Models;

namespace sv_8d8308971df64ee7bf94d753abe5eb69.Services;

/// <summary>
/// Singleton store for wizard state, keyed by session ID.
/// Both static (SSR) and interactive (Server) components access this
/// to bridge the render-mode boundary.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionKey)
    {
        return _states.GetOrAdd(sessionKey, _ => new WizardState());
    }

    public void Remove(string sessionKey)
    {
        _states.TryRemove(sessionKey, out _);
    }
}

namespace sv_8d8308971df64ee7bf94d753abe5eb69.Services;

/// <summary>
/// Ensures every request has a wizard session cookie so that both static
/// layout rendering and interactive page circuits share the same session key.
/// </summary>
public class WizardSessionMiddleware
{
    private readonly RequestDelegate _next;
    public const string CookieName = "wizard_session";

    public WizardSessionMiddleware(RequestDelegate next)
    {
        _next = next;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        if (!context.Request.Cookies.ContainsKey(CookieName))
        {
            var sessionId = Guid.NewGuid().ToString("N");
            context.Response.Cookies.Append(CookieName, sessionId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                IsEssential = true,
                MaxAge = TimeSpan.FromHours(4)
            });
            // Make the value available to downstream components on this first request
            context.Items[CookieName] = sessionId;
        }

        await _next(context);
    }
}

