using System.Collections.Concurrent;
using sv_8d8308971df64ee7bf94d753abe5eb69.Models;

namespace sv_8d8308971df64ee7bf94d753abe5eb69.Services;

/// <summary>
/// Singleton store for wizard state, keyed by session ID.
/// Both static (SSR) and interactive (Server) components access this
/// to bridge the render-mode boundary.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionKey)
    {
        return _states.GetOrAdd(sessionKey, _ => new WizardState());
    }

    public void Remove(string sessionKey)
    {
        _states.TryRemove(sessionKey, out _);
    }
}

