@using sv_8d8308971df64ee7bf94d753abe5eb69.Services
@inherits LayoutComponentBase
@inject WizardStateStore Store
@inject NavigationManager Nav

@{
    // Resolve session key from the HttpContext cookie (available during static SSR)
    var sessionKey = GetSessionKey();
    var state = sessionKey is not null ? Store.GetOrCreate(sessionKey) : null;
    var currentStep = GetCurrentStep();
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <div class="wizard-progress d-flex align-items-center gap-3 w-100">
                <span class="fw-semibold me-2">Step @currentStep of 4</span>

                @for (int i = 1; i <= 4; i++)
                {
                    var step = i;
                    var isActive = step == currentStep;
                    var isComplete = step switch
                    {
                        1 => state?.Step1Complete == true,
                        2 => state?.Step2Complete == true,
                        3 => state?.Step3Complete == true,
                        4 => false,
                        _ => false
                    };
                    var href = step switch
                    {
                        1 => "apply/personal-info",
                        2 => "apply/experience",
                        3 => "apply/references",
                        4 => "apply/review",
                        _ => ""
                    };
                    var label = step switch
                    {
                        1 => "Personal Info",
                        2 => "Experience",
                        3 => "References",
                        4 => "Review",
                        _ => ""
                    };

                    <a href="@href"
                       class="wizard-step @(isActive ? "active" : "") @(isComplete ? "complete" : "")">
                        <span class="wizard-step-number">@step</span>
                        <span class="wizard-step-label d-none d-md-inline">@label</span>
                    </a>
                }
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private string? GetSessionKey()
    {
        if (HttpContext is null) return null;

        if (HttpContext.Request.Cookies.TryGetValue(WizardSessionMiddleware.CookieName, out var cookie))
            return cookie;

        // First request before the cookie round-trips
        if (HttpContext.Items.TryGetValue(WizardSessionMiddleware.CookieName, out var item))
            return item as string;

        return null;
    }

    private int GetCurrentStep()
    {
        var uri = Nav.ToBaseRelativePath(Nav.Uri).TrimEnd('/');
        return uri switch
        {
            "apply/personal-info" => 1,
            "apply/experience" => 2,
            "apply/references" => 3,
            "apply/review" => 4,
            _ => 1
        };
    }
}

.wizard-progress {
    flex-wrap: wrap;
}

.wizard-step {
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    padding: 0.3rem 0.75rem;
    border-radius: 1rem;
    background: #e9ecef;
    color: #495057;
    text-decoration: none;
    font-size: 0.875rem;
    transition: background 0.15s, color 0.15s;
}

.wizard-step:hover {
    background: #dee2e6;
    text-decoration: none;
    color: #212529;
}

.wizard-step.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.wizard-step.complete {
    background: #198754;
    color: #fff;
}

.wizard-step.complete.active {
    background: #0d6efd;
}

.wizard-step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.5rem;
    height: 1.5rem;
    border-radius: 50%;
    background: rgba(255,255,255,0.3);
    font-weight: 700;
    font-size: 0.8rem;
}

