@page "/apply/personal-info"
@layout WizardLayout
@rendermode InteractiveServer

@using sv_8d8308971df64ee7bf94d753abe5eb69.Models
@using sv_8d8308971df64ee7bf94d753abe5eb69.Services

@inject WizardStateStore Store
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

@if (_state is not null)
{
    <EditForm Model="_model" OnValidSubmit="HandleNext" FormName="personal-info">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Full Name</label>
            <InputText class="form-control" @bind-Value="_model.Name" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email Address</label>
            <InputText class="form-control" @bind-Value="_model.Email" />
        </div>

        <div class="d-flex justify-content-end">
            <button type="submit" class="btn btn-primary">Next →</button>
        </div>
    </EditForm>
}

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private WizardState? _state;
    private PersonalInfoModel _model = new();
    private string _sessionKey = "";

    protected override void OnInitialized()
    {
        _sessionKey = ResolveSessionKey();
        _state = Store.GetOrCreate(_sessionKey);

        // Pre-fill from existing state
        _model.Name = _state.Name;
        _model.Email = _state.Email;
    }

    private void HandleNext()
    {
        _state!.Name = _model.Name;
        _state.Email = _model.Email;
        _state.Step1Complete = true;

        Nav.NavigateTo("apply/experience");
    }

    private string ResolveSessionKey()
    {
        // During prerender, HttpContext is available
        if (HttpContext is not null)
        {
            if (HttpContext.Request.Cookies.TryGetValue(WizardSessionMiddleware.CookieName, out var cookie))
                return cookie;
            if (HttpContext.Items.TryGetValue(WizardSessionMiddleware.CookieName, out var item))
                return (string)item!;
        }
        return "";
    }

    private class PersonalInfoModel
    {
        public string Name { get; set; } = "";
        public string Email { get; set; } = "";
    }
}

