@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer

@using sv_8d8308971df64ee7bf94d753abe5eb69.Models
@using sv_8d8308971df64ee7bf94d753abe5eb69.Services

@inject WizardStateStore Store
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@if (_state is not null)
{
    <div class="mb-4">
        @for (int i = 0; i < _entries.Count; i++)
        {
            var index = i;
            <div class="card mb-3">
                <div class="card-body">
                    <div class="d-flex justify-content-between align-items-center mb-2">
                        <h6 class="card-title mb-0">Position @(index + 1)</h6>
                        <button type="button" class="btn btn-sm btn-outline-danger"
                                @onclick="() => RemoveEntry(index)">Remove</button>
                    </div>

                    <div class="mb-2">
                        <label class="form-label">Company</label>
                        <input class="form-control" @bind="_entries[index].Company" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Job Title</label>
                        <input class="form-control" @bind="_entries[index].Title" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Duration</label>
                        <input class="form-control" @bind="_entries[index].Duration"
                               placeholder="e.g. Jan 2020 – Mar 2023" />
                    </div>
                </div>
            </div>
        }

        <button type="button" class="btn btn-outline-secondary" @onclick="AddEntry">
            + Add Position
        </button>
    </div>

    <div class="d-flex justify-content-between">
        <button type="button" class="btn btn-secondary" @onclick="HandleBack">← Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
    </div>
}

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private WizardState? _state;
    private List<JobEntry> _entries = new();
    private string _sessionKey = "";

    protected override void OnInitialized()
    {
        _sessionKey = ResolveSessionKey();
        _state = Store.GetOrCreate(_sessionKey);

        // Deep-copy existing entries so edits don't mutate state until saved
        _entries = _state.JobHistory
            .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Duration = j.Duration })
            .ToList();

        if (_entries.Count == 0)
            _entries.Add(new JobEntry());
    }

    private void AddEntry() => _entries.Add(new JobEntry());
    private void RemoveEntry(int index) => _entries.RemoveAt(index);

    private void SaveState()
    {
        _state!.JobHistory = _entries
            .Select(e => new JobEntry { Company = e.Company, Title = e.Title, Duration = e.Duration })
            .ToList();
        _state.Step2Complete = true;
    }

    private void HandleNext()
    {
        SaveState();
        Nav.NavigateTo("apply/references");
    }

    private void HandleBack()
    {
        SaveState();
        Nav.NavigateTo("apply/personal-info");
    }

    private string ResolveSessionKey()
    {
        if (HttpContext is not null)
        {
            if (HttpContext.Request.Cookies.TryGetValue(WizardSessionMiddleware.CookieName, out var cookie))
                return cookie;
            if (HttpContext.Items.TryGetValue(WizardSessionMiddleware.CookieName, out var item))
                return (string)item!;
        }
        return "";
    }
}

