+                        <h6 class="card-title mb-0">Reference @(index + 1)</h6>
+                        <button type="button" class="btn btn-sm btn-outline-danger"
+                                @onclick="() => RemoveRef(index)">Remove</button>
+                    </div>
+
+                    <div class="mb-2">
+                        <label class="form-label">Name</label>
+                        <input class="form-control" @bind="_refs[index].Name" />
+                    </div>
+                    <div class="mb-2">
+                        <label class="form-label">Email</label>
+                        <input class="form-control" @bind="_refs[index].Email" />
+                    </div>
+                    <div class="mb-2">
+                        <label class="form-label">Relationship</label>
+                        <input class="form-control" @bind="_refs[index].Relationship"
+                               placeholder="e.g. Former Manager" />
+                    </div>
+                </div>
+            </div>
+        }
+
+        <button type="button" class="btn btn-outline-secondary" @onclick="AddRef">
+            + Add Reference
+        </button>
+    </div>
+
+    <div class="d-flex justify-content-between">
+        <button type="button" class="btn btn-secondary" @onclick="HandleBack">← Back</button>
+        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
+    </div>
+}
+
+@code {
+    [CascadingParameter]
+    public HttpContext? HttpContext { get; set; }
+
+    private WizardState? _state;
+    private List<ReferenceContact> _refs = new();
+    private string _sessionKey = "";
+
+    protected override void OnInitialized()
+    {
+        _sessionKey = ResolveSessionKey();
+        _state = Store.GetOrCreate(_sessionKey);
+
+        _refs = _state.References
+            .Select(r => new ReferenceContact { Name = r.Name, Email = r.Email, Relationship = r.Relationship })
+            .ToList();
+
+        if (_refs.Count == 0)
+            _refs.Add(new ReferenceContact());
+    }
+
+    private void AddRef() => _refs.Add(new ReferenceContact());
+    private void RemoveRef(int index) => _refs.RemoveAt(index);
+
+    private void SaveState()
+    {
+        _state!.References = _refs
+            .Select(r => new ReferenceContact { Name = r.Name, Email = r.Email, Relationship = r.Relationship })
+            .ToList();
+        _state.Step3Complete = true;
+    }
+
+    private void HandleNext()
+    {
+        SaveState();
+        Nav.NavigateTo("apply/review");
+    }
+
+    private void HandleBack()
+    {
+        SaveState();
+        Nav.NavigateTo("apply/experience");
+    }
+
+    private string ResolveSessionKey()
+    {
+        if (HttpContext is not null)
+        {
+            if (HttpContext.Request.Cookies.TryGetValue(WizardSessionMiddleware.CookieName, out var cookie))
+                return cookie;
+            if (HttpContext.Items.TryGetValue(WizardSessionMiddleware.CookieName, out var item))
+                return (string)item!;
+        }
+        return "";
+    }
+}
