toolArgs.file_text:
@page "/apply/review"
@layout WizardLayout
@rendermode InteractiveServer

@using sv_8d8308971df64ee7bf94d753abe5eb69.Models
@using sv_8d8308971df64ee7bf94d753abe5eb69.Services

@inject WizardStateStore Store
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

@if (_state is not null)
{
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@(_state.Name is { Length: > 0 } name ? name : "—")</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@(_state.Email is { Length: > 0 } email ? email : "—")</dd>
            </dl>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work Experience</strong>
            <a href="apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @if (_state.JobHistory.Count == 0)
            {
                <p class="text-muted mb-0">No positions added.</p>
            }
            else
            {
                @foreach (var job in _state.JobHistory)
                {
                    <div class="mb-2">
                        <strong>@job.Title</strong> at @job.Company
                        <br />
                        <small class="text-muted">@job.Duration</small>
                    </div>
                }
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @if (_state.References.Count == 0)
            {
                <p class="text-muted mb-0">No references added.</p>
            }
            else
            {
                @foreach (var r in _state.References)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> — @r.Relationship
                        <br />
                        <small class="text-muted">@r.Email</small>
                    </div>
                }
            }
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button type="button" class="btn btn-secondary" @onclick="HandleBack">← Back</button>
        <button type="button" class="btn btn-success" @onclick="HandleSubmit">
            Submit Application
        </button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">
            Your application has been submitted successfully!
        </div>
    }
}

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private WizardState? _state;
    private string _sessionKey = "";
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionKey = ResolveSessionKey();
        _state = Store.GetOrCreate(_sessionKey);
    }

    private void HandleBack()
    {
        Nav.NavigateTo("apply/references");
    }

    private void HandleSubmit()
    {
        // In a real app you'd persist to a database here
        _submitted = true;
    }

    private string ResolveSessionKey()
    {
        if (HttpContext is not null)
        {
            if (HttpContext.Request.Cookies.TryGetValue(WizardSessionMiddleware.CookieName, out var cookie))
                return cookie;
            if (HttpContext.Items.TryGetValue(WizardSessionMiddleware.CookieName, out var item))
                return (string)item!;
        }
        return "";
    }
}

